INSERT INTO t_p71821556_real_estate_catalog_.ai_memory (key, value, updated_at) VALUES

-- Общая структура округов
('geo_krasnodar_okrugs', 'Краснодар делится на 4 административных округа: Центральный, Карасунский, Прикубанский, Западный. Каждый округ включает несколько районов и посёлков.', NOW()),

-- Центральный округ
('geo_okrug_centralny', 'Центральный округ Краснодара — деловое и историческое ядро города. Включает районы: ЦМР (центр), Кожзавод, Табачка (ХБК), Аэропорт. Здесь расположены главные деловые улицы: Красная, Ставропольская, Северная. Максимальные арендные ставки в городе, высокая концентрация офисов класса А и Б, ресторанов, банков, ритейла.', NOW()),
('geo_okrug_centralny_districts', 'Районы Центрального округа Краснодара: ЦМР (Центральный микрорайон) — ул. Красная, исторический центр; Кожзавод — набережная Кубани, лофт-формат; Табачка/ХБК — редевелопмент промзоны; Аэропорт — ул. Дзержинского, транзитный трафик; РИП — бывший завод приборов.', NOW()),

-- Карасунский округ
('geo_okrug_karasunsky', 'Карасунский округ Краснодара — самый населённый округ, расположен в центре и на юге города. Включает крупные жилые массивы: ФМР, ЮМР, ЧМР, КМР, ГМР, СМР, МХГ, КСК, Музыкальный. Развитая торговая инфраструктура: ТЦ Галактика, МегаМаг, Галерея Краснодар. Крупнейшие торговые коридоры: ул. Ставропольская, Красных Партизан, Героев-Разведчиков.', NOW()),
('geo_okrug_karasunsky_districts', 'Районы Карасунского округа Краснодара: ФМР (Фестивальный) — ТЦ МегаМаг, Галерея; ЮМР (Юбилейный) — ул. Героев-Разведчиков; ЧМР (Черёмушки) — спальный массив; КМР (Комсомольский) — ТЦ Галактика, ул. Ставропольская; ГМР (Гидростроителей) — ТЦ Красная Площадь; СМР (Славянский) — ул. Тургенева, Селезнёва; МХГ (Микрохирургия глаза) — медкластер; КСК — бывший комбинат; Музыкальный — новостройки; Черёмушки — ЧМР; ШМР (Школьный) — семейный район.', NOW()),

-- Прикубанский округ
('geo_okrug_prikubansky', 'Прикубанский округ Краснодара — восточная и северо-восточная часть города. Включает районы: Пашковский (ПМР), СХИ, Российский посёлок, Северный посёлок, Колосистый, Калинина, район 40 лет Победы, Витаминкомбинат, ЗИП, Индустриальный. Здесь расположен аэропорт Пашковский. Смешанная застройка: жилая, промышленная, новые ЖК.', NOW()),
('geo_okrug_prikubansky_districts', 'Районы Прикубанского округа Краснодара: ПМР (Пашковский) — аэропорт, крупный жилой и промышленный район; СХИ — университетский район (КубГАУ); Российский посёлок — активная застройка; Северный посёлок — растущий район; 40 лет Победы — спальный массив; Витаминкомбинат — промзона; ЗИП — бывший завод; Индустриальный посёлок — производственный; Колосистый посёлок — частная застройка; Калинина сады — садоводческий массив.', NOW()),

-- Западный округ
('geo_okrug_zapadny', 'Западный округ Краснодара — западная и южная часть города. Включает: Губернский, Немецкая деревня, Авиагородок, Лазурный, Новознаменский, Краснодарский посёлок, Победитель, Плодородный, Берёзовый, Западный обход, ТЭЦ. Активное жилое строительство, коттеджные посёлки, логистические зоны вдоль западного обхода. Наиболее динамично развивающийся округ по объёму нового жилья.', NOW()),
('geo_okrug_zapadny_districts', 'Районы Западного округа Краснодара: Губернский — элитный жилой район; Немецкая деревня — коттеджный посёлок бизнес-класса; Авиагородок — новостройки у бывшего аэропорта; Лазурный посёлок — малоэтажное строительство; Новознаменский посёлок — частная застройка; Краснодарский посёлок — смешанная застройка; Победитель посёлок — частный сектор; Плодородный посёлок — малонаселённый; Берёзовый посёлок — частный сектор; Западный обход — логистическая зона; ТЭЦ — промышленная зона.', NOW()),

-- Особые зоны и кластеры
('geo_special_zones', 'Особые коммерческие зоны Краснодара: Стадион Краснодар (Панорама) — в Карасунском округе, высокий событийный трафик; Красная площадь ТЦ — в Карасунском/ГМР, крупнейший ТЦ ЮФО; Западный обход — логистический коридор федерального значения; 9-й километр — промышленно-складская зона.', NOW()),

-- Популярные запросы по районам
('geo_district_abbr', 'Расшифровка аббревиатур районов Краснодара: ЦМР = Центральный микрорайон (центр города); ФМР = Фестивальный микрорайон; ЮМР = Юбилейный микрорайон; ЧМР = Черёмушки; КМР = Комсомольский микрорайон; ГМР = Гидростроителей микрорайон; СМР = Славянский микрорайон; МХГ = микрорайон Микрохирургии глаза; КСК = Камвольно-суконный комбинат; ПМР = Пашковский микрорайон; СХИ = Сельхозинститут; ШМР = Школьный микрорайон; ХБК = Хлопчатобумажный комбинат; ТЭЦ = район теплоэлектростанции; ЗИП = Завод измерительных приборов; РИП = Завод радиоизмерительных приборов; КСК = Камвольно-суконный комбинат.', NOW()),

-- Коммерческая специализация по округам
('geo_commercial_central', 'Центральный округ: лучшие офисы класса А/Б, флагманский ритейл на ул. Красной, рестораны и отели. Самые высокие ставки аренды. Подходит для: юридических фирм, банков, представительств, бутиков, ресторанного бизнеса, гостиниц.', NOW()),
('geo_commercial_karasunsky', 'Карасунский округ: крупнейшие торговые центры (ТЦ Галактика, МегаМаг, Галерея), стрит-ритейл, медицина, фитнес, общепит. Умеренные ставки при высоком трафике. ФМР и ЮМР — лучшие в округе по покупательской активности.', NOW()),
('geo_commercial_prikubansky', 'Прикубанский округ: производственные, складские объекты, автосервисы. ПМР — гостиницы и сервис для аэропорта. СХИ — студенческий формат. Новые ЖК в Российском и Северном посёлках — перспективный ритейл и услуги. Умеренные и низкие ставки.', NOW()),
('geo_commercial_zapadny', 'Западный округ: логистика и склады вдоль Западного обхода, элитная торговля в Губернском и Немецкой деревне, сервис для новосёлов в Авиагородке и Лазурном. Самые низкие ставки в городе при растущем потенциале.', NOW()),

-- Подсказки по автоопределению района
('geo_autodetect_tips', 'При определении района Краснодара по адресу: ул. Красная, Мира, Северная, Ленина — ЦМР (Центральный округ); ул. Ставропольская, Красных Партизан, Героев-Разведчиков — Карасунский округ; р-н Пашковский, ул. Нефтяников, Путевая — Прикубанский округ (ПМР); ул. Западный обход, р-н Губернский, Немецкая деревня — Западный округ. Районы у аэропорта Краснодар (Пашковский) относятся к Прикубанскому округу.', NOW()),

-- Сравнение районов для клиентов
('geo_district_comparison', 'Рекомендации по выбору района Краснодара для бизнеса: офис/представительство → ЦМР, ФМР, ЮМР; торговля у дома → КМР, ГМР, ЧМР, СМР, ШМР; ресторан/кафе → ЦМР, Панорама (стадион), ФМР; склад/производство → Западный обход, ТЭЦ, Витаминкомбинат, ЗИП, 9-й километр; гостиница → ЦМР, ПМР (у аэропорта); элитный бизнес → Губернский, Немецкая деревня; студенческий формат → СХИ; медицина → МХГ, ККБ.', NOW())

